/**
 * List currencies supported by the billing system.
 * @summary List currencies
 */
export const ListCurrenciesQueryParams = zod.object({
  filter: zod
    .object({
      code: zod
        .union([
          zod.coerce.string(),
          zod.object({
            contains: zod.coerce
              .string()
              .optional()
              .describe('Value contains the given string value (fuzzy match).'),
            eq: zod.coerce
              .string()
              .optional()
              .describe('Value strictly equals the given string value.'),
            exists: zod.coerce
              .boolean()
              .optional()
              .describe(
                'When true, the field must be present (non-null); when false, the field must be\nabsent (null).',
              ),
            gt: zod.coerce
              .string()
              .optional()
              .describe(
                'Value is greater than the given string value (lexicographic compare).',
              ),
            gte: zod.coerce
              .string()
              .optional()
              .describe(
                'Value is greater than or equal to the given string value (lexicographic\ncompare).',
              ),
            lt: zod.coerce
              .string()
              .optional()
              .describe(
                'Value is less than the given string value (lexicographic compare).',
              ),
            lte: zod.coerce
              .string()
              .optional()
              .describe(
                'Value is less than or equal to the given string value (lexicographic compare).',
              ),
            neq: zod.coerce
              .string()
              .optional()
              .describe('Value does not equal the given string value.'),
            ocontains: zod.coerce
              .string()
              .optional()
              .describe(
                'Returns entities that fuzzy-match any of the comma-delimited phrases in the\nfilter string.',
              ),
            oeq: zod.coerce
              .string()
              .optional()
              .describe(
                'Returns entities that exact match any of the comma-delimited phrases in the\nfilter string.',
              ),
          }),
        ])
        .optional()
        .describe(
          'Filters on the given string field value by either exact or fuzzy match. All\nproperties are optional; provide exactly one to specify the comparison.',
        ),
      type: zod
        .enum(['fiat', 'custom'])
        .optional()
        .describe(
          'Currency type for custom currencies. It should be a unique code but not\nconflicting with any existing standard currency codes.',
        ),
    })
    .optional()
    .describe(
      'Filter currencies returned in the response.\n\nTo filter currencies by type add the following query param: filter[type]=custom',
    ),
  page: zod
    .object({
      number: zod.coerce.number().optional().describe('The page number.'),
      size: zod.coerce
        .number()
        .optional()
        .describe('The number of items to include per page.'),
    })
    .optional()
    .describe('Determines which page of the collection to retrieve.'),
  sort: zod.coerce
    .string()
    .optional()
    .describe(
      'Sort currencies returned in the response. Supported sort attributes are:\n\n- `code` (default)\n- `name`\n\nThe `asc` suffix is optional as the default sort order is ascending. The `desc`\nsuffix is used to specify a descending order.',
    ),
})

