export const listCreditGrantsPathCustomerIdRegExp =
  /^[0-7][0-9A-HJKMNP-TV-Z]{25}$/

export const ListCreditGrantsParams = zod.object({
  customerId: zod.coerce.string().regex(listCreditGrantsPathCustomerIdRegExp),
})

export const listCreditGrantsQueryFilterCurrencyOneMin = 3
export const listCreditGrantsQueryFilterCurrencyOneMax = 3

export const listCreditGrantsQueryFilterCurrencyOneRegExp = /^[A-Z]{3}$/

export const ListCreditGrantsQueryParams = zod.object({
  filter: zod
    .object({
      currency: zod.coerce
        .string()
        .min(listCreditGrantsQueryFilterCurrencyOneMin)
        .max(listCreditGrantsQueryFilterCurrencyOneMax)
        .regex(listCreditGrantsQueryFilterCurrencyOneRegExp)
        .describe(
          'Three-letter [ISO4217](https://www.iso.org/iso-4217-currency-codes.html)\ncurrency code. Custom three-letter currency codes are also supported for\nconvenience.',
        )
        .optional()
        .describe('Filter credit grants by currency.'),
      status: zod
        .enum(['pending', 'active', 'expired', 'voided'])
        .describe(
          'Credit grant lifecycle status.\n\n- `pending`: The credit block has been created but is not yet valid.\n(`effective_at` is in the future or availability_policy is not met)\n- `active`: The credit block is currently valid and eligible for consumption.\n(`effective_at` is in the past, `expires_at` is in the future and\navailability_policy is met)\n- `expired`: The credit block expired with remaining unused balance,\n`expires_at` time has passed.\n- `voided`: The credit block was voided. Remaining balance is forfeited.',
        )
        .optional()
        .describe('Filter credit grants by status.'),
    })
    .optional()
    .describe('Filter credit grants returned in the response.'),
  page: zod
    .object({
      number: zod.coerce.number().optional().describe('The page number.'),
      size: zod.coerce
        .number()
        .optional()
        .describe('The number of items to include per page.'),
    })
    .optional()
    .describe('Determines which page of the collection to retrieve.'),
})

