/**
 * Update the payment settlement status of an externally funded credit grant.

Use this endpoint to synchronize the payment state of an external payment with
the system so that revenue recognition and credit availability work as expected.
 * @summary Update credit grant external settlement status
 */
export const updateCreditGrantExternalSettlementPathCustomerIdRegExp =
  /^[0-7][0-9A-HJKMNP-TV-Z]{25}$/
export const updateCreditGrantExternalSettlementPathCreditGrantIdRegExp =
  /^[0-7][0-9A-HJKMNP-TV-Z]{25}$/

export const UpdateCreditGrantExternalSettlementParams = zod.object({
  creditGrantId: zod.coerce
    .string()
    .regex(updateCreditGrantExternalSettlementPathCreditGrantIdRegExp),
  customerId: zod.coerce
    .string()
    .regex(updateCreditGrantExternalSettlementPathCustomerIdRegExp),
})

export const UpdateCreditGrantExternalSettlementBody = zod
  .object({
    status: zod
      .enum(['pending', 'authorized', 'settled'])
      .describe(
        'Credit purchase payment settlement status.\n\n- `pending`: Payment has been initiated and is not yet authorized.\n- `authorized`: Payment has been authorized.\n- `settled`: Payment has been settled.',
      )
      .describe('The new payment settlement status.'),
  })
  .describe(
    'Request body for updating the external payment settlement status of a credit\ngrant.',
  )

